const webhookData = $input.first().json;
// Handle webhook body data - jobDescription can be in body or directly in json
const jobDescription = webhookData.body?.jobDescription || webhookData.jobDescription || '';
// Extract key from webhook data (for PDF naming: key-R.pdf, key-CL.pdf)
const key = webhookData.body?.key ?? webhookData.key ?? 0;

if (!jobDescription) {
  throw new Error('Job Description is required. Send POST with JSON: {"jobDescription": "...", "key": 0}');
}

return [{
  json: {
    jobDescription: jobDescription,
    key: key
  }
}];

const resumeData = $input.first().json;

let resumeHtml = '';
let resumePlainText = '';

if (resumeData.resumeHtml) {
  resumeHtml = resumeData.resumeHtml;
  resumePlainText = resumeHtml
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
} else if (resumeData.binary?.resume) {
  const buffer = Buffer.from(resumeData.binary.resume.data, 'base64');
  resumeHtml = buffer.toString('utf-8');
  resumePlainText = resumeHtml
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Truncate plain text to ~8000 chars to avoid exceeding Claude's token limit
if (resumePlainText.length > 8000) {
  resumePlainText = resumePlainText.substring(0, 8000);
}

const previousData = $('Prepare Input').first().json;

return [{
  json: {
    ...previousData,
    resumeHtml: resumeHtml,
    resumePlainText: resumePlainText,
    resumeFileName: resumeData.fileName || 'resume',
    jdAnalysis: resumeData.jdAnalysis || {},
    jobDescription: resumeData.jobDescription || previousData.jobDescription || ''
  }
}];

