const response = $input.first().json;
let coverLetterData;

try {
  const content = response.output || response.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    coverLetterData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in AI response');
  }
} catch (e) {
  coverLetterData = {
    cover_letter_text: 'Error generating cover letter: ' + e.message,
    key_points_highlighted: [],
    tone_analysis: 'N/A',
    error: e.message
  };
}

const previousData = $('Extract Resume Content').first().json;

return [{
  json: {
    ...previousData,
    coverLetter: coverLetterData.cover_letter_text,
    keyPoints: coverLetterData.key_points_highlighted || [],
    toneAnalysis: coverLetterData.tone_analysis || ''
  }
}];

const data = $input.first().json;

// Get current date
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// Create cover letter HTML with same style as resume
const coverLetterHtml = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>YOUR NAME - Cover Letter</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }

    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&display=swap');

    body {
      font-family: "Inter", sans-serif;
      font-size: 11pt;
      line-height: 1.4;
      color: #000;
      background: #fff;
    }

    .page {
      max-width: 8.5in;
      margin: 0 auto;
      padding: 0.75in;
    }

    @page {
      size: Letter portrait;
      margin: 0;
    }

    @media print {
      body {
        -webkit-print-color-adjust: exact;
        print-color-adjust: exact;
        margin: 0;
        padding: 0;
      }
      .page {
        padding: 0.75in;
      }
    }

    .header {
      text-align: center;
      margin-bottom: 20pt;
    }

    .name {
      font-size: 24pt;
      font-weight: bold;
      margin-bottom: 2pt;
      color: #1a3a6e;
    }

    .contact {
      font-size: 11pt;
    }

    .contact a {
      color: #0066cc;
      text-decoration: underline;
    }

    .date {
      margin-bottom: 20px;
      font-size: 11pt;
      margin-top: 20pt;
    }

    .content {
      white-space: pre-wrap;
      word-wrap: break-word;
    }

    .content p {
      margin-bottom: 15px;
      text-align: justify;
    }
  </style>
</head>
<body>
  <div class="page">
    <header class="header">
      <h1 class="name">YOUR NAME</h1>
      <p class="contact">555-555-5555 | <a href="mailto:your.email@example.com">your.email@example.com</a> | Your City, Province | <a href="https://linkedin.com/in/yourlinkedinprofile">LinkedIn</a> | <a href="https://github.com/yourgithubusername">GitHub</a></p>
    </header>

    <div class="date">${dateStr}</div>

    <div class="content">${data.coverLetter || 'Cover letter content not available'}</div>
  </div>
</body>
</html>`;

const fileName = `CoverLetter_${data.jdAnalysis.company_name || 'Company'}_${Date.now()}`.replace(/[^a-zA-Z0-9_]/g, '_');

return [{
  json: {
    ...data,
    coverLetterHtml: coverLetterHtml,
    fileName: fileName
  },
  binary: {
    coverLetter: await this.helpers.prepareBinaryData(
      Buffer.from(coverLetterHtml, 'utf-8'),
      `${fileName}.html`,
      'text/html; charset=utf-8'
    )
  }
}];

const input = $input.first();
// Get key from Prepare Input node for PDF naming
const prepareInputData = $('Prepare Input').first().json;
const key = prepareInputData.key ?? 0;

let htmlContent = '';

if (input.json.coverLetterHtml) {
  htmlContent = input.json.coverLetterHtml;
} else if (input.binary && input.binary.coverLetter) {
  htmlContent = Buffer.from(input.binary.coverLetter.data, 'base64').toString('utf-8');
} else {
  throw new Error('No HTML content found');
}

const fileName = input.json.fileName || `cover_letter_${Date.now()}`;

return [{
  json: {
    htmlContent: htmlContent,
    fileName: fileName,
    key: key
  },
  binary: {
    htmlFile: {
      data: Buffer.from(htmlContent).toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const input = $input.first();
// Get key from Prepare Input node for PDF naming
const prepareInputData = $('Prepare Input').first().json;
const key = prepareInputData.key ?? 0;

let htmlContent = '';

// Option 1: Get HTML from upstream Generate Resume HTML node (json.resumeHtml)
if (input.json.resumeHtml) {
  htmlContent = input.json.resumeHtml;
}
// Option 2: Get HTML from binary data (binary.resume)
else if (input.binary && input.binary.resume) {
  htmlContent = Buffer.from(input.binary.resume.data, 'base64').toString('utf-8');
}
else {
  throw new Error('No HTML content found from upstream node');
}

// Fixed page settings for resume
const pageSize = 'Letter';
const orientation = 'portrait';

// Use fileName from upstream or generate default
const fileName = input.json.fileName || `resume_${Date.now()}`;

return [{
  json: {
    htmlContent: htmlContent,
    pageSize: pageSize,
    orientation: orientation,
    fileName: fileName,
    key: key
  }
}];

// SIMPLIFIED: Page spacing is now controlled by template file
// This node only prepares HTML for Gotenberg (requires file named 'index.html')

const data = $input.first().json;
const htmlContent = data.htmlContent;
const key = data.key ?? 0;

// No need to inject any styles - template already has @page and .page padding
// Just pass through the HTML content as-is
const finalHtml = htmlContent;

return [{
  json: {
    htmlContent: finalHtml,
    pageSize: data.pageSize,
    orientation: data.orientation,
    fileName: data.fileName,
    key: key,
    info: 'Page spacing controlled by template file'
  },
  binary: {
    htmlFile: {
      data: Buffer.from(finalHtml).toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const input = $input.first();
const previousData = $('Prepare for PDF Conversion').first().json;

if (!input.binary) {
  throw new Error('No binary data received from conversion service');
}

const pdfBinary = input.binary.data;
if (!pdfBinary) {
  throw new Error('No PDF data found. Available keys: ' + Object.keys(input.binary).join(', '));
}

// Use key from workflow for PDF naming: {key}-CL.pdf
const key = previousData.key ?? 0;
const fileName = `${key}-CL.pdf`;

return [{
  json: {
    success: true,
    fileName: fileName,
    filePath: `/home/node/.n8n-files/data/${fileName}`,
    key: key
  },
  binary: {
    pdf: {
      ...pdfBinary,
      fileName: fileName,
      mimeType: 'application/pdf'
    }
  }
}];

const input = $input.first();
const previousData = $('Convert to PDF').first().json;

if (!input.binary) {
  throw new Error('No binary data received from conversion service');
}

const pdfBinary = input.binary.data;
if (!pdfBinary) {
  throw new Error('No PDF data found. Available keys: ' + Object.keys(input.binary).join(', '));
}

// Use key from workflow for PDF naming: {key}-R.pdf
const key = previousData.key ?? 0;
const fileName = `${key}-R.pdf`;

return [{
  json: {
    success: true,
    fileName: fileName,
    filePath: `/home/node/.n8n-files/data/${fileName}`,
    key: key
  },
  binary: {
    pdf: {
      ...pdfBinary,
      fileName: fileName,
      mimeType: 'application/pdf'
    }
  }
}];
